fn test_e2e_key_input_and_render() {
    let mut harness = E2EHarness::new("input_output", "key_input", 80, 24);

    // Create an editor
    let mut buffer = EditBuffer::with_text("Hello");
    let mut view = EditorView::new(buffer);

    // Inject arrow key input
